package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlinx.coroutines.test.*
import kotlin.test.*

/**
 * Tests for the fix to SharedFlow.toList(destination) and SharedFlow.toSet(destination)
 *
 * Issue: In version 1.7.0-Beta, these methods ignored the destination parameter
 * Fix: Pass the destination parameter to the underlying Flow.toList() / Flow.toSet() methods
 *
 * Note: SharedFlow.toList/toSet are deprecated because SharedFlow never completes,
 * but they should still work correctly for testing purposes when cancelled.
 */
class SharedFlowToListTest {

    @Test
    fun testSharedFlowToListWithCustomDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 1)

        // Emit some values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        val customList = mutableListOf<Int>()

        // Collect into the custom list
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @OptIn(ExperimentalCoroutinesApi::class)
            sharedFlow.toList(customList)
        }

        // Wait a bit to collect values, then cancel (SharedFlow never completes)
        delay(10)
        job.cancel()
        job.join()

        // Verify that values were collected into the custom list
        // With the bug: customList would be empty or only have the initial replay value
        // With the fix: customList should contain values from sharedFlow
        assertTrue(customList.isNotEmpty(),
            "Expected customList to contain values from SharedFlow, but it was empty. " +
            "This indicates the bug where toList() ignores the destination parameter.")

        // The list should have at least the replay value
        assertTrue(customList.contains(3),
            "Expected customList to contain the emitted value 3 (replay cache). Actual: $customList")
    }

    @Test
    fun testSharedFlowToSetWithCustomDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 1)

        // Emit some values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        val customSet = mutableSetOf<Int>()

        // Collect into the custom set
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @OptIn(ExperimentalCoroutinesApi::class)
            sharedFlow.toSet(customSet)
        }

        // Wait a bit to collect values, then cancel
        delay(10)
        job.cancel()
        job.join()

        // Verify that values were collected into the custom set
        assertTrue(customSet.isNotEmpty(),
            "Expected customSet to contain values from SharedFlow, but it was empty. " +
            "This indicates the bug where toSet() ignores the destination parameter.")

        // The set should have at least the replay value
        assertTrue(customSet.contains(3),
            "Expected customSet to contain the emitted value 3 (replay cache). Actual: $customSet")
    }

    @Test
    fun testSharedFlowToListDestinationIsReturned() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 1)

        // Emit a value
        sharedFlow.emit(42)

        val customList = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @OptIn(ExperimentalCoroutinesApi::class)
            val result = sharedFlow.toList(customList)
            // Verify that the returned list is the same object as customList
            assertSame(customList, result,
                "Expected toList() to return the same destination list. " +
                "This indicates the bug where toList() creates a new list.")
        }

        delay(10)
        job.cancel()
        job.join()
    }

    @Test
    fun testSharedFlowToSetDestinationIsReturned() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 1)

        // Emit a value
        sharedFlow.emit(42)

        val customSet = mutableSetOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @OptIn(ExperimentalCoroutinesApi::class)
            val result = sharedFlow.toSet(customSet)
            // Verify that the returned set is the same object as customSet
            assertSame(customSet, result,
                "Expected toSet() to return the same destination set. " +
                "This indicates the bug where toSet() creates a new set.")
        }

        delay(10)
        job.cancel()
        job.join()
    }

    @Test
    fun testSharedFlowToListMultipleEmissions() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 2)

        val customList = mutableListOf<Int>()

        // Start collecting
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @OptIn(ExperimentalCoroutinesApi::class)
            sharedFlow.toList(customList)
        }

        // Emit multiple values
        repeat(10) { i ->
            sharedFlow.emit(i)
            delay(1)
        }

        // Cancel to stop collection
        job.cancel()
        job.join()

        // With the bug: customList would be empty
        // With the fix: customList should contain multiple values
        assertTrue(customList.size > 2,
            "Expected customList to contain multiple values. Received ${customList.size}. " +
            "This indicates the bug where toList() ignores the destination parameter.")

        println("Collected ${customList.size} values: $customList")
    }
}"}

